import Foundation
import SwiftData

enum UserSeedData {

    static func seedIfNeeded(context: ModelContext) {
        // Check for a specific seed user rather than user count,
        // so seeding still runs even if the user signed up first.
        let seedName = "mario"
        let descriptor = FetchDescriptor<User>(predicate: #Predicate { $0.username == seedName })
        let count = (try? context.fetchCount(descriptor)) ?? 0
        guard count == 0 else { return }
        seed(context: context)
    }

    // MARK: - Tag cache

    private static var tagCache: [String: Tag] = [:]

    private static func tag(_ name: String, context: ModelContext) -> Tag {
        if let existing = tagCache[name] { return existing }
        let t = Tag(name: name)
        context.insert(t)
        tagCache[name] = t
        return t
    }

    // MARK: - Helpers

    private static func ing(_ qty: Double, _ unit: String, _ name: String) -> Ingredient {
        Ingredient(quantity: qty, unit: unit, name: name)
    }

    private static func make(
        _ name: String,
        servings: Double,
        instructions: String,
        tags tagNames: [String],
        ingredients: [Ingredient],
        user: User,
        context: ModelContext
    ) -> Recipe {
        let recipe = Recipe(
            name: name,
            servings: servings,
            instructions: instructions.trimmingCharacters(in: .whitespacesAndNewlines),
            isPublic: true,
            creatorID: user.id,
            creatorName: user.displayName
        )
        for tagName in tagNames {
            recipe.tags.append(tag(tagName, context: context))
        }
        for ingredient in ingredients {
            context.insert(ingredient)
            recipe.ingredients.append(ingredient)
        }
        return recipe
    }

    // MARK: - Main seed

    private static func seed(context: ModelContext) {
        tagCache = [:]

        let users = createUsers(context: context)
        for user in users {
            context.insert(user)
        }

        var allRecipes: [Recipe] = []
        allRecipes += marioRecipes(user: users[0], context: context)
        allRecipes += priyaRecipes(user: users[1], context: context)
        allRecipes += chenRecipes(user: users[2], context: context)
        allRecipes += sofiaRecipes(user: users[3], context: context)
        allRecipes += jeanRecipes(user: users[4], context: context)
        allRecipes += yukiRecipes(user: users[5], context: context)
        allRecipes += fatimaRecipes(user: users[6], context: context)
        allRecipes += jamesRecipes(user: users[7], context: context)
        allRecipes += nanaRecipes(user: users[8], context: context)
        allRecipes += emmaRecipes(user: users[9], context: context)

        for r in allRecipes { context.insert(r) }
        try? context.save()
    }

    private static func createUsers(context: ModelContext) -> [User] {
        [
            User(username: "mario", displayName: "Mario Rossi", passwordHash: AuthStore.hashPassword("mario")),
            User(username: "priya", displayName: "Priya Sharma", passwordHash: AuthStore.hashPassword("priya")),
            User(username: "chen", displayName: "Chen Wei", passwordHash: AuthStore.hashPassword("chen")),
            User(username: "sofia", displayName: "Sofia Garcia", passwordHash: AuthStore.hashPassword("sofia")),
            User(username: "jean", displayName: "Jean Dupont", passwordHash: AuthStore.hashPassword("jean")),
            User(username: "yuki", displayName: "Yuki Tanaka", passwordHash: AuthStore.hashPassword("yuki")),
            User(username: "fatima", displayName: "Fatima Al-Rashid", passwordHash: AuthStore.hashPassword("fatima")),
            User(username: "james", displayName: "James Wilson", passwordHash: AuthStore.hashPassword("james")),
            User(username: "nana", displayName: "Nana Osei", passwordHash: AuthStore.hashPassword("nana")),
            User(username: "emma", displayName: "Emma Lindqvist", passwordHash: AuthStore.hashPassword("emma")),
        ]
    }

